import{_ as a,o as l,c as i,ag as e}from"./chunks/framework.BqfgOMAh.js";const c=JSON.parse('{"title":"NexusFlow Skill","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/agent-skill.md","filePath":"zh/guide/agent-skill.md"}'),t={name:"zh/guide/agent-skill.md"};function n(o,s,h,p,d,r){return l(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="nexusflow-skill" tabindex="-1">NexusFlow Skill <a class="header-anchor" href="#nexusflow-skill" aria-label="Permalink to &quot;NexusFlow Skill&quot;">​</a></h1><p>NexusFlow Skill 是独立发布的 Agent 使用说明包，用于帮助 Cursor、Claude Code 以及其他支持 skills.sh / AGENTS 说明的工具，更稳定地使用 NexusFlow 桌面应用提供的 MCP Server。</p><p>仓库地址：<a href="https://github.com/maxzhao/nexusflow-skill" target="_blank" rel="noreferrer">https://github.com/maxzhao/nexusflow-skill</a></p><p>安装命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> maxzhao/nexusflow-skill</span></span></code></pre></div><p>它不是 NexusFlow 桌面主程序的一部分，也不是把外部 Skill 接入 NexusFlow 主程序的插件。它的作用是：<strong>让外部 IDE / Agent 知道如何安全使用 NexusFlow MCP 工具</strong>。</p><h2 id="使用前提" tabindex="-1">使用前提 <a class="header-anchor" href="#使用前提" aria-label="Permalink to &quot;使用前提&quot;">​</a></h2><p>安装 NexusFlow Skill 前，请先准备好 NexusFlow 运行环境：</p><ol><li>已安装并启动 NexusFlow 桌面应用。</li><li>已在 NexusFlow 中启用 MCP 模式。</li><li>你的 IDE / MCP Client 已连接到 NexusFlow MCP endpoint。</li><li>如需执行 UE 操作，Unreal Engine 已打开，NexusFlow UE 插件已安装并连接。</li></ol><p>如果这些条件还没满足，请先阅读 <a href="./mcp">在 IDE / Agent 中使用 NexusFlow</a>。</p><h2 id="它解决什么问题" tabindex="-1">它解决什么问题 <a class="header-anchor" href="#它解决什么问题" aria-label="Permalink to &quot;它解决什么问题&quot;">​</a></h2><p>外部 Agent 直接看到 MCP 工具时，可能不知道：</p><ul><li>应该先检查 NexusFlow 与 UE 是否连接；</li><li>应该先读取当前 UE 上下文，而不是猜测资产或蓝图状态；</li><li>应该先搜索并加载 NexusFlow Skill 指南，再执行动作；</li><li>什么时候需要加载知识主题；</li><li>为什么直接执行 Python 应该作为最后手段。</li></ul><p>NexusFlow Skill 把这些规则写成可安装的 Agent 指令，帮助 Agent 按稳定、安全的流程完成 UE 操作。</p><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><p>在支持 skills.sh 的环境中运行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> maxzhao/nexusflow-skill</span></span></code></pre></div><p>如果你所在网络访问 GitHub 不稳定，需要为 Git / npm 配置代理。例如：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ALL_PROXY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">socks5://127.0.0.1:10808</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">HTTPS_PROXY=http://127.0.0.1:10808 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">HTTP_PROXY=http://127.0.0.1:10808 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npx </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> maxzhao/nexusflow-skill</span></span></code></pre></div><h2 id="包含的入口" tabindex="-1">包含的入口 <a class="header-anchor" href="#包含的入口" aria-label="Permalink to &quot;包含的入口&quot;">​</a></h2><p>安装后，Skill 仓库中包含面向不同 Agent 的入口文件：</p><table tabindex="0"><thead><tr><th>文件</th><th>适用环境</th></tr></thead><tbody><tr><td><code>SKILL.md</code></td><td>通用 Skill 入口</td></tr><tr><td><code>AGENTS.md</code></td><td>读取 AGENTS 指令的 Agent / IDE</td></tr><tr><td><code>CLAUDE.md</code></td><td>Claude Code</td></tr><tr><td><code>.cursor/rules/nexusflow.mdc</code></td><td>Cursor</td></tr><tr><td><code>references/mcp-tools.md</code></td><td>MCP 工具细节参考</td></tr></tbody></table><p>多数情况下，你只需要通过 skills.sh 安装；具体文件由对应工具读取。</p><h2 id="agent-应遵循的流程" tabindex="-1">Agent 应遵循的流程 <a class="header-anchor" href="#agent-应遵循的流程" aria-label="Permalink to &quot;Agent 应遵循的流程&quot;">​</a></h2><p>安装后，Agent 应优先使用以下渐进式流程：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>get_connection_status</span></span>
<span class="line"><span>  -&gt; get_ue_context</span></span>
<span class="line"><span>  -&gt; search_skills</span></span>
<span class="line"><span>  -&gt; load_skill</span></span>
<span class="line"><span>  -&gt; [load_knowledge]</span></span>
<span class="line"><span>  -&gt; execute_action</span></span></code></pre></div><p>关键规则：</p><ul><li>MCP Client 显示的实时 tool list 和 schema 是最终事实来源。</li><li>任何 UE 或 Blueprint 操作前都要先调用 <code>get_connection_status</code>。</li><li>连接成功后调用 <code>get_ue_context</code>，不要脱离 UE 当前上下文猜测。</li><li>优先搜索并加载 NexusFlow Skill，而不是直接执行 Python。</li><li>同一会话不要重复加载同一个 Skill、知识主题或模板。</li><li>写操作后必须验证结果。</li><li>遇到 <code>USER_CANCELLED</code> 立即停止。</li></ul><h2 id="适合谁使用" tabindex="-1">适合谁使用 <a class="header-anchor" href="#适合谁使用" aria-label="Permalink to &quot;适合谁使用&quot;">​</a></h2><ul><li>希望在 Cursor 中让 AI 操作 UE 蓝图的开发者。</li><li>希望在 Claude Code 中使用 NexusFlow MCP 工具链的技术用户。</li><li>想把 NexusFlow 当作 UE 自动化 MCP 网关接入自定义 Agent 的团队。</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./mcp">在 IDE / Agent 中使用 NexusFlow</a>：了解 MCP 连接要求和可用工具。</li><li><a href="./blueprint-operations">蓝图操作</a>：了解 NexusFlow 内置蓝图能力。</li></ul>`,32)])])}const u=a(t,[["render",n]]);export{c as __pageData,u as default};
